import{_ as r,o,c as a,a0 as n}from"./chunks/framework.DV6pVIgV.js";const p=JSON.parse('{"title":"雲端安全","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/13.md","filePath":"clf-c02/13.md","lastUpdated":1783610848000}'),e={name:"clf-c02/13.md"};function d(s,t,i,l,g,h){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="雲端安全" tabindex="-1">雲端安全 <a class="header-anchor" href="#雲端安全" aria-label="Permalink to &quot;雲端安全&quot;">​</a></h1><p>IAM、加密、威脅偵測與合規。這章服務最多，重點在分清楚每個服務解決什麼問題。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>認證（Authentication）</strong></p><ul><li><a href="https://www.cloudflare.com/learning/access-management/what-is-authentication/" target="_blank" rel="noreferrer">Cloudflare：What is authentication（英文）</a></li><li><a href="https://learn.microsoft.com/zh-tw/entra/identity-platform/authentication-vs-authorization" target="_blank" rel="noreferrer">Microsoft Learn：比較驗證與授權（繁中）</a></li></ul></li><li><p><strong>授權（Authorization）</strong></p><ul><li><a href="https://learn.microsoft.com/zh-tw/entra/identity-platform/authentication-vs-authorization" target="_blank" rel="noreferrer">Microsoft Learn：比較驗證與授權（繁中）</a></li></ul></li><li><p><strong>DDoS（分散式阻斷服務攻擊，Distributed Denial of Service）</strong></p><ul><li><a href="https://www.cloudflare.com/learning/ddos/what-is-a-ddos-attack/" target="_blank" rel="noreferrer">Cloudflare：What is a DDoS attack（英文）</a></li><li><a href="https://www.cloudflare.com/zh-tw/ddos/" target="_blank" rel="noreferrer">Cloudflare：DDoS 攻擊是什麼（繁中）</a></li></ul></li></ul><h2 id="責任共擔模型" tabindex="-1">責任共擔模型 <a class="header-anchor" href="#責任共擔模型" aria-label="Permalink to &quot;責任共擔模型&quot;">​</a></h2><p>AWS 管「雲本身的安全」（Security OF the Cloud），你管「雲裡面的安全」（Security IN the Cloud）。</p><p>你的資料、你的 IAM 權限設定，永遠是你的責任，不管用哪種服務。這章講的所有工具，都是幫你做好「IN the Cloud」這一半。</p><h2 id="iam-identity-and-access-management" tabindex="-1">IAM（Identity and Access Management） <a class="header-anchor" href="#iam-identity-and-access-management" aria-label="Permalink to &quot;IAM（Identity and Access Management）&quot;">​</a></h2><p>IAM 管「誰（身分）能對哪些資源做什麼（權限）」。可以想成公司的門禁系統：發識別證、分部門、訂每個人能進哪些門。</p><p>IAM 是<strong>全球服務（Global）</strong>，不綁特定 Region——你建的使用者在所有 Region 都通用。</p><h3 id="最小權限原則-principle-of-least-privilege" tabindex="-1">最小權限原則（Principle of Least Privilege） <a class="header-anchor" href="#最小權限原則-principle-of-least-privilege" aria-label="Permalink to &quot;最小權限原則（Principle of Least Privilege）&quot;">​</a></h3><blockquote><p><strong>只給「完成工作所需的最小權限」，不多給一點。</strong></p></blockquote><p>這是整個 IAM 設計的核心思想：</p><ul><li><strong>起點是零</strong>：新建 User / Role 預設什麼都做不了，需要什麼才加什麼，而不是先給到飽再慢慢收</li><li><strong>縮小爆炸半徑（Blast Radius）</strong>：帳號萬一被盜，攻擊者只能做那個帳號權限範圍內的事——授權限得愈小，損失愈小</li><li><strong>避免萬用字元</strong>：IAM Policy 寫 <code>&quot;Action&quot;: &quot;*&quot;</code> 代表「什麼操作都能做」，看起來方便，實際上是最容易出問題的設定；應精確指定實際需要的動作</li></ul><h3 id="iam-核心元件" tabindex="-1">IAM 核心元件 <a class="header-anchor" href="#iam-核心元件" aria-label="Permalink to &quot;IAM 核心元件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>元件</th><th>是什麼</th><th>類比</th></tr></thead><tbody><tr><td><strong>Root User</strong>（根使用者）</td><td>用 email 註冊帳號時建立的最高權限帳號</td><td>創辦人的萬能鑰匙</td></tr><tr><td><strong>IAM User</strong>（使用者）</td><td>給「一個人或應用」的長期身分</td><td>員工識別證</td></tr><tr><td><strong>IAM Group</strong>（群組）</td><td>一群使用者的集合，套同一組權限</td><td>部門</td></tr><tr><td><strong>IAM Policy</strong>（政策）</td><td>用 JSON 寫的權限清單，定義允許/拒絕什麼</td><td>權限明細表</td></tr><tr><td><strong>IAM Role</strong>（角色）</td><td>臨時憑證，不綁特定人，誰需要誰「擔任」</td><td>臨時通行證</td></tr></tbody></table><h3 id="root-user-建立後就鎖起來" tabindex="-1">Root User：建立後就鎖起來 <a class="header-anchor" href="#root-user-建立後就鎖起來" aria-label="Permalink to &quot;Root User：建立後就鎖起來&quot;">​</a></h3><p>Root User 權力過大（可關帳號、改帳單），最佳實踐是日常絕對不要用它。正確做法：</p><ol><li>立刻幫 Root User 開 <strong>MFA</strong>（多因素驗證）†</li><li>建立 IAM 使用者來做日常工作</li><li>Root User 只在極少數必須的操作（如改帳戶設定）才動用</li></ol><blockquote><p>† 自 re:Inforce 2025 起，AWS 對所有帳號的 root user <strong>強制</strong>啟用 MFA——現為平台要求，不只是最佳實踐。</p></blockquote><h3 id="iam-user-vs-iam-role" tabindex="-1">IAM User vs IAM Role <a class="header-anchor" href="#iam-user-vs-iam-role" aria-label="Permalink to &quot;IAM User vs IAM Role&quot;">​</a></h3><p>兩者都能持有權限，差別在「有沒有長期憑證」：</p><table tabindex="0"><thead><tr><th></th><th>IAM User</th><th>IAM Role</th></tr></thead><tbody><tr><td>對象</td><td>固定的一個人 / 應用</td><td>不綁人，誰需要誰臨時擔任</td></tr><tr><td>憑證</td><td>長期帳密 / 存取金鑰</td><td>臨時、會自動過期</td></tr><tr><td>典型場景</td><td>工程師登入 Console</td><td>EC2 要存取 S3、跨帳號存取、第三方聯合登入</td></tr></tbody></table><blockquote><p>「EC2 上的應用程式要存取 S3，該怎麼做？」→ 指派一個 <strong>IAM Role</strong> 給 EC2，不要把存取金鑰寫死在程式或主機裡。（用角色拿臨時憑證，不用長期金鑰。）</p></blockquote><hr><h4 id="mfa-multi-factor-authentication-多因素驗證" tabindex="-1">MFA（Multi-Factor Authentication，多因素驗證） <a class="header-anchor" href="#mfa-multi-factor-authentication-多因素驗證" aria-label="Permalink to &quot;MFA（Multi-Factor Authentication，多因素驗證）&quot;">​</a></h4><p>帳密只是「你<strong>知道</strong>的東西」，一旦外洩攻擊者立刻能登入。MFA 在密碼之後加一個「你<strong>擁有</strong>的東西」，兩個因素都對才能進去：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>登入流程：輸入密碼 → 再提供動態驗證碼（6 位數、30 秒換一次）→ 才能成功登入</span></span></code></pre></div><p>AWS 支援三種 MFA 裝置：</p><table tabindex="0"><thead><tr><th>類型</th><th>說明</th><th>代表例子</th></tr></thead><tbody><tr><td><strong>Virtual MFA（虛擬 MFA）</strong></td><td>手機 App 每 30 秒產生一組動態碼（TOTP）</td><td>Google Authenticator、Authy</td></tr><tr><td><strong>Hardware TOTP token</strong></td><td>實體小裝置，每 30 秒顯示一組數字</td><td>第三方廠商實體 token</td></tr><tr><td><strong>FIDO Security Key</strong></td><td>插 USB 或 NFC 輕碰的硬體金鑰</td><td>YubiKey</td></tr></tbody></table><blockquote><p>Root User 必須開 MFA：Root User 是整個 AWS 帳號的最高權限，設定完就要鎖起來不日常使用，並立刻開啟 MFA。有管理員權限的 IAM User 也強烈建議開啟。</p></blockquote><h3 id="iam-identity-center-原-aws-sso" tabindex="-1">IAM Identity Center（原 AWS SSO） <a class="header-anchor" href="#iam-identity-center-原-aws-sso" aria-label="Permalink to &quot;IAM Identity Center（原 AWS SSO）&quot;">​</a></h3><p>當你有很多 AWS 帳號 / 很多使用者時，用 <strong>IAM Identity Center</strong> 做單一登入（SSO），一處集中管理，還能接公司既有的目錄（如 Active Directory）。</p><h3 id="aws-organizations-與-scp" tabindex="-1">AWS Organizations 與 SCP <a class="header-anchor" href="#aws-organizations-與-scp" aria-label="Permalink to &quot;AWS Organizations 與 SCP&quot;">​</a></h3><p>企業用雲一段時間後，往往會有多個 AWS 帳號——開發、測試、生產各一個，或不同部門、子公司各自的帳號。<strong>AWS Organizations</strong> 就是把這些帳號集中到一個組織下統一管理的服務。</p><p><strong>為什麼要分帳號？</strong> 帳號是 AWS 最強的安全隔離邊界——同帳號內的資源彼此「看得到」，不同帳號預設完全隔離。大組織讓不同環境（dev / prod）或不同業務單位各自一個帳號，Organizations 再把這些帳號「管起來」。</p><p>Organizations 可以把帳號分組成 <strong>OU（Organizational Unit，組織單位）</strong>，像一棵樹——你可以在不同 OU 套不同的管控政策：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Root（根）</span></span>
<span class="line"><span>├── OU：生產環境</span></span>
<span class="line"><span>│   ├── 帳號 A（Web 服務）</span></span>
<span class="line"><span>│   └── 帳號 B（後端服務）</span></span>
<span class="line"><span>├── OU：開發環境</span></span>
<span class="line"><span>│   └── 帳號 C（測試）</span></span>
<span class="line"><span>└── OU：安全與日誌</span></span>
<span class="line"><span>    └── 帳號 D（集中記錄）</span></span></code></pre></div><p><strong>合併帳單（Consolidated Billing）</strong>：Organizations 也能把所有帳號的費用合進一張帳單，還能讓多帳號用量合計享量大折扣——詳見帳單那章。</p><hr><p><strong>SCP（Service Control Policy，服務控制政策）</strong> 設的是「<strong>權限上限 / 邊界</strong>」，不是直接授權。例如用 SCP 規定「這個 OU 底下所有帳號都不准用 us-east-1 以外的 Region」。即使某帳號的 IAM Policy 給了更多權限，也會被 SCP 的上限擋住。</p><blockquote><p><strong>最終權限 = IAM 給的 ∩ SCP 允許的</strong></p></blockquote><blockquote><p>† <strong>RCP（Resource Control Policies，資源控制政策）</strong>：2024 年新增的姊妹機制。SCP 管「<strong>身分</strong>能做什麼動作的上限」，RCP 管「<strong>資源</strong>能被誰存取的上限」——兩者合力從不同維度設天花板。CLF 知道有這個機制即可；細節偏 SAA。</p></blockquote><h2 id="iam-vs-security-group-nacl" tabindex="-1">IAM vs Security Group／NACL <a class="header-anchor" href="#iam-vs-security-group-nacl" aria-label="Permalink to &quot;IAM vs Security Group／NACL&quot;">​</a></h2><blockquote><p>兩個都叫「安全」，守的卻是不同的東西</p></blockquote><p>讀到這裡，AWS 有兩組「安全規則」：這章的 IAM，和前面學過的 Security Group／NACL。它們常被混在一起——都叫「安全」、都用「允許／拒絕」的語言。但它們其實守在<strong>完全不同的兩層</strong>。</p><p>它們各自回答的，是兩個毫不相干的問題：</p><ul><li><strong>IAM</strong> 回答：「這個身分，能不能對 AWS 下某個操作指令？」——例如能不能呼叫 API 去建立、讀取、刪除某個 AWS 資源。它在乎的是「你是誰、被授權做哪些動作」，屬於控制台／API 這一層。</li><li><strong>Security Group／NACL</strong> 回答：「這個網路封包，能不能抵達或離開某台機器／子網？」——它根本看不到你的 AWS 身分是誰，只看封包的來源 IP、目的 port、協定，屬於網路流量這一層。</li></ul><blockquote><p>封包能不能到達 EC2 的 <strong>port 22</strong> → <strong>Security Group／NACL</strong> 說了算（網路層）</p><p>你能不能在 AWS 裡把這台 EC2 <strong>建立、停止、終止</strong> → <strong>IAM</strong> 說了算（API 層）</p></blockquote><p>關鍵在於兩者互不替代：一個 IAM 權限開到最大的管理員，如果 Security Group 沒放行 22，一樣 SSH 不進去；反過來，Security Group 全開，也不代表某個 IAM 使用者就有權呼叫 API 把這台機器關掉。它們各守一層，缺一不可。</p><table tabindex="0"><thead><tr><th>比較</th><th>IAM（＋ SCP）</th><th>Security Group／NACL</th></tr></thead><tbody><tr><td>守的層面</td><td>AWS 控制台／API：能對 AWS 資源做什麼<strong>操作</strong></td><td>網路流量：封包能不能<strong>抵達</strong>機器／子網</td></tr><tr><td>判斷依據</td><td>你是誰、被授權哪些<strong>動作</strong></td><td>封包的<strong>來源 IP／port／協定</strong></td></tr><tr><td>看得到你的 AWS 身分嗎</td><td>是（身分就是它的核心）</td><td>否（只看封包）</td></tr><tr><td>典型問題</td><td>「能不能呼叫 API 讀這個 S3 bucket？」</td><td>「HTTP 封包能不能連到這台 Web server？」</td></tr></tbody></table><blockquote><p>SCP 雖然也能「拒絕」，但它拒絕的是帳號能執行哪些 API 動作，跟 NACL 拒絕網路封包是不同層。SCP 其實跟 IAM 同一邊（都在管「身分／動作」），只是它管的是整個帳號的權限上限。</p></blockquote><h2 id="資料加密與金鑰管理" tabindex="-1">資料加密與金鑰管理 <a class="header-anchor" href="#資料加密與金鑰管理" aria-label="Permalink to &quot;資料加密與金鑰管理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>服務</th><th>功能</th><th>使用時機</th></tr></thead><tbody><tr><td><strong>KMS</strong>（Key Management Service）</td><td>AWS 託管的加密金鑰服務</td><td>大多數加密需求的標準答案</td></tr><tr><td><strong>CloudHSM</strong></td><td>專用硬體安全模組（HSM），金鑰完全由你掌控</td><td>法規硬性要求專屬硬體時使用</td></tr><tr><td><strong>ACM</strong>（Certificate Manager）</td><td>配發 / 管理 SSL/TLS 憑證</td><td>要讓網站跑 HTTPS、幫 ALB / CloudFront 上憑證</td></tr><tr><td><strong>Secrets Manager</strong></td><td>安全存放密碼 / API 金鑰，可自動輪替</td><td>程式要用 DB 密碼、又想定期自動換</td></tr></tbody></table><h2 id="威脅偵測與調查" tabindex="-1">威脅偵測與調查 <a class="header-anchor" href="#威脅偵測與調查" aria-label="Permalink to &quot;威脅偵測與調查&quot;">​</a></h2><p>這五個服務最常一起出現在選項裡：</p><table tabindex="0"><thead><tr><th>服務</th><th>一句話</th><th>抓什麼 / 範圍</th></tr></thead><tbody><tr><td><strong>GuardDuty</strong></td><td>威脅偵測</td><td>分析 VPC Flow Logs、DNS、CloudTrail 日誌，找惡意/異常行為</td></tr><tr><td><strong>Inspector</strong></td><td>漏洞掃描</td><td>掃 EC2 / 容器映像 / Lambda 的軟體漏洞與不當設定</td></tr><tr><td><strong>Macie</strong></td><td>敏感資料發現</td><td>用 ML 找 S3 裡的 PII / 敏感資料（限 S3）</td></tr><tr><td><strong>Security Hub</strong></td><td>集中儀表板</td><td>彙整 GuardDuty / Inspector / Macie 等的發現到單一視圖</td></tr><tr><td><strong>Detective</strong></td><td>根因調查</td><td>把發現的安全問題深入分析、找根本原因</td></tr></tbody></table><ul><li>抓「惡意行為 / 未授權存取」（看日誌找壞人）→ <strong>GuardDuty</strong></li><li>抓「漏洞 / 該打的修補程式 / CVE」→ <strong>Inspector</strong></li><li>找「S3 裡的個資 / PII / 敏感資料」→ <strong>Macie</strong></li><li>要「跨帳號集中看所有安全發現」→ <strong>Security Hub</strong></li><li>要「調查事件根本原因」→ <strong>Detective</strong></li></ul><h2 id="網路與應用層防護" tabindex="-1">網路與應用層防護 <a class="header-anchor" href="#網路與應用層防護" aria-label="Permalink to &quot;網路與應用層防護&quot;">​</a></h2><table tabindex="0"><thead><tr><th>服務</th><th>防什麼</th><th>重點</th></tr></thead><tbody><tr><td><strong>Shield</strong></td><td>DDoS 攻擊</td><td>Standard 自動啟用、免費、人人有；Advanced 付費，含 24/7 支援與成本保護</td></tr><tr><td><strong>WAF</strong>（Web Application Firewall）</td><td>L7 網頁攻擊</td><td>依規則過濾 HTTP/HTTPS，擋 SQL Injection、XSS</td></tr><tr><td><strong>Network Firewall</strong></td><td>VPC 層級網路流量</td><td>對整個 VPC 做網路流量過濾</td></tr><tr><td><strong>Firewall Manager</strong></td><td>跨帳號集中管理</td><td>統一管理多帳號的 WAF / Shield 規則</td></tr></tbody></table><p>其中 Shield 分兩個等級，差別非常大：</p><table tabindex="0"><thead><tr><th></th><th>Shield Standard</th><th>Shield Advanced</th></tr></thead><tbody><tr><td><strong>費用</strong></td><td>免費，自動啟用</td><td>付費（月費 + 流量費）</td></tr><tr><td><strong>申請方式</strong></td><td>不需要，人人都有</td><td>需主動訂閱</td></tr><tr><td><strong>防護對象</strong></td><td>所有 AWS 資源（自動）</td><td>EC2、ELB、CloudFront、Route 53、Global Accelerator</td></tr><tr><td><strong>攻擊類型</strong></td><td>常見 L3/L4 DDoS（流量淹沒、SYN flood…）</td><td>同上，加上更複雜的攻擊</td></tr><tr><td><strong>DDoS 應變團隊（DRT）</strong></td><td>無</td><td>24/7 專人支援</td></tr><tr><td><strong>費用保護</strong></td><td>無</td><td>DDoS 導致資源暴增的帳單可申請退款</td></tr><tr><td><strong>進階監控與告警</strong></td><td>無</td><td>有（近即時可見度）</td></tr></tbody></table><p><strong>什麼時候需要 Shield Advanced？</strong> 你的服務是高知名度、高流量的公共網站或應用——例如電商大促、遊戲發布、金融服務——且需要 AWS 的 DDoS 應變團隊（DRT）在攻擊時直接介入協助、事後還能追討被灌爆的帳單，這才值得訂 Advanced。一般情境 Standard 就夠了。</p><blockquote><p>📌 <strong>WAF vs Shield</strong>：擋「應用層攻擊（SQLi / XSS）」→ WAF；擋「流量灌爆的 DDoS」→ Shield。</p></blockquote><h2 id="合規-compliance" tabindex="-1">合規（Compliance） <a class="header-anchor" href="#合規-compliance" aria-label="Permalink to &quot;合規（Compliance）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>服務 / 概念</th><th>是什麼</th></tr></thead><tbody><tr><td><strong>AWS Artifact</strong></td><td>下載 AWS 的合規報告（SOC、PCI DSS、ISO 等），交給稽核單位看</td></tr><tr><td><strong>AWS Audit Manager</strong></td><td>自動蒐集證據、協助你跑稽核流程</td></tr></tbody></table><blockquote><p>Artifact 只是「<strong>拿現成的合規報告</strong>」的地方，它不會幫你做稽核、也不監控你的設定。要「追蹤設定變更是否合規」是 <strong>AWS Config</strong> （下一章介紹）。</p></blockquote><h2 id="考試重點整理" tabindex="-1">考試重點整理 <a class="header-anchor" href="#考試重點整理" aria-label="Permalink to &quot;考試重點整理&quot;">​</a></h2><ul><li>責任共擔：AWS 管雲本身（OF），你管雲裡面（IN）；資料與 IAM 設定永遠是你的責任</li><li>IAM 是<strong>全球服務</strong>；五元件：<strong>Root User</strong>（鎖起來別用、開 MFA）、<strong>User</strong>（人）、<strong>Group</strong>（部門）、<strong>Policy</strong>（JSON 權限）、<strong>Role</strong>（臨時憑證）</li><li><strong>User vs Role</strong>：要長期身分用 User；EC2 / 服務 / 跨帳號要存取資源用 Role（臨時憑證，不寫死金鑰）</li><li><strong>最小權限原則</strong> + <strong>MFA</strong> 是 IAM 最佳實踐的兩大關鍵字</li><li><strong>SCP</strong>（Organizations）設「權限上限」，不是授權；最終權限 = IAM ∩ SCP</li><li>加密：<strong>KMS</strong>（標準）、<strong>CloudHSM</strong>（法規要專屬硬體才用）、<strong>ACM</strong>（SSL/TLS 憑證）、<strong>Secrets Manager</strong>（密碼自動輪替）</li><li>威脅偵測：<strong>GuardDuty</strong>（惡意行為）、<strong>Inspector</strong>（漏洞）、<strong>Macie</strong>（S3 個資）、<strong>Security Hub</strong>（集中彙整）、<strong>Detective</strong>（查根因）</li><li>網路防護：<strong>Shield</strong>（DDoS，Standard 免費自動）、<strong>WAF</strong>（L7，擋 SQLi/XSS）、<strong>Network Firewall</strong>（VPC 流量）、<strong>Firewall Manager</strong>（跨帳號管理）</li><li>合規：<strong>Artifact</strong> = 下載報告（不做稽核/監控）</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>EC2 上的程式要存取 S3</td><td>指派 <strong>IAM Role</strong> 給 EC2（不要寫死金鑰）</td></tr><tr><td>控制「誰能對 AWS 資源下操作指令」</td><td><strong>IAM</strong>（＋跨帳號上限用 SCP）</td></tr><tr><td>控制「什麼網路流量能連到機器」</td><td><strong>Security Group／NACL</strong>（M5）</td></tr><tr><td>偵測帳號內的惡意/異常行為（看日誌）</td><td><strong>GuardDuty</strong></td></tr><tr><td>掃描 EC2 / 容器的軟體漏洞</td><td><strong>Inspector</strong></td></tr><tr><td>找出 S3 裡有沒有個資（PII）</td><td><strong>Macie</strong></td></tr><tr><td>跨多帳號集中看所有安全告警</td><td><strong>Security Hub</strong></td></tr><tr><td>自動防護 DDoS（基本、免費）</td><td><strong>Shield Standard</strong></td></tr><tr><td>擋 SQL Injection、XSS 等網頁攻擊</td><td><strong>WAF</strong></td></tr><tr><td>下載 PCI DSS / SOC 合規報告</td><td><strong>AWS Artifact</strong></td></tr><tr><td>大多數情況管理加密金鑰</td><td><strong>KMS</strong></td></tr><tr><td>法規要求專屬硬體保管金鑰</td><td><strong>CloudHSM</strong></td></tr><tr><td>自動輪替資料庫密碼</td><td><strong>Secrets Manager</strong></td></tr><tr><td>限制某些帳號只能用特定 Region</td><td><strong>SCP</strong>（AWS Organizations）</td></tr></tbody></table>`,70)])])}const u=r(e,[["render",d]]);export{p as __pageData,u as default};
